ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_CFG_TRANSP_EIN" CHECK (TRANSPORT_EINHEIT in ('LTE', 'LHM', 'LTE_LTE', 'LTE_LHM')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_EDITOR_SPERRE" CHECK (EDITOR_SPERRE in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_ENABLED" CHECK (ENABLED in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_AUFS_PUNKT" CHECK (IS_AUFSETZ_PUNKT in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_BRING_GESP" CHECK (IS_BRINGEN_GESPERRT in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_DEFEKT" CHECK (IS_DEFEKT in ('F', 'T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_ENTSCH_PKT" CHECK (IS_ENTSCHEID_PUNKT in (0,1,2)) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_HOLEN_GESP" CHECK (IS_HOLEN_GESPERRT in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_IPUNKT" CHECK (IS_IPUNKT in (0,1,2,3)) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_RBG" CHECK (IS_RBG in ('F', 'T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_IS_ZIEL" CHECK (IS_ZIEL in (0,1,2)) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_LVS_TRANSP_E" CHECK (LVS_TRANSP_EVENT in( 0,1,2,3)) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "CHK_MFR_ELEMENT_STRAT_DEF_MOEG" CHECK (STRATEGIE_DEFEKT_MOEGL in (0,1,2,3)) ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "PK_MFR_ELEMENT_CFG" PRIMARY KEY ("ELEMENT_ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."MFR_ELEMENT_CFG" ADD CONSTRAINT "UX_MFR_ELEMENT_CFG_FAHRZ" UNIQUE ("FAHRZEUG")
  USING INDEX  ENABLE;


